SELECT ROUND(
    COUNT(CASE WHEN status IN (0, 1, 9) THEN 1 END) * 100.0 / NULLIF(COUNT(*), 0), 2
) FROM ht_scope WHERE tasks_id = #{taskId}

SELECT COUNT(*) AS total, SUM(CASE WHEN is_special = 1 THEN 1 ELSE 0 END) AS specialCount, SUM(CASE WHEN status = 9 THEN 1 ELSE 0 END) AS completedCount, SUM(CASE WHEN status IN (0, 1, 9) THEN 1 ELSE 0 END) AS normalCount, ROUND( COUNT(CASE WHEN status IN (0, 1, 9) THEN 1 END) * 100.0 / NULLIF(COUNT(*), 0), 2 ) AS balanceRate, ROUND(AVG(out_temp), 2) AS avgReturnTemp, SUM(CASE WHEN in_temp IS NOT NULL AND in_temp < 40 THEN 1 ELSE 0 END) AS lowInTempCount, SUM(CASE WHEN room_temp IS NOT NULL AND room_temp < 18 THEN 1 ELSE 0 END) AS lowRoomTempCount FROM ht_scope WHERE org_id = #{orgId}
AND building_id = #{buildingId}
AND unit_id = #{unitCode}

