INSERT INTO ht_task_setting_log (id, task_id, create_by, create_time, scope_type)
SELECT #{newMainId}, a.task_id, #{createBy}, NOW(), '1'
FROM ht_task_setting_log a WHERE a.id = #{logId}

INSERT INTO ht_task_setting_log (id, task_id, create_by, create_time, scope_type)
SELECT #{newMainId}, a.task_id, #{createBy}, NOW(), '2'
FROM ht_task_setting_log a WHERE a.id = #{logId}

INSERT INTO ht_task_setting_log_item (id, main_id, scope_type, meter_num, meter_id, old_angle, new_angle)
SELECT REPLACE(UUID(), '-', ''), #{newMainId}, '1', a.meter_num, a.meter_id, a.old_angle, a.new_angle
FROM ht_task_setting_log_item a WHERE a.main_id = #{oldMainId}

INSERT INTO ht_task_setting_log_item (id, main_id, scope_type, meter_num, meter_id, old_angle, new_angle)
