UPDATE ht_tasks
SET execution_time = #{executionTime},
    out_temp_pj = #{average}
WHERE id = #{tasksId}

mapper.select:
SELECT
    ROUND(IFNULL(d.standardN, '0') / IFNULL(b.total, '0') * '100', '0') AS standardNow
FROM ht_tasks a
LEFT JOIN (
    SELECT COUNT(id) AS total, tasks_id FROM ht_scope WHERE is_special <> '1' GROUP BY tasks_id
) b ON b.tasks_id = a.id
LEFT JOIN (
    SELECT COUNT(id) AS standardN, tasks_id FROM ht_scope WHERE status = '9' AND is_special <> '1' GROUP BY tasks_id
) d ON d.tasks_id = a.id
WHERE a.id = #{tasksId}

SELECT
    ROUND(IFNULL(d.standardN, '0') / IFNULL(b.total, '0') * '100', '0') AS standardNow
FROM ht_tasks a
LEFT JOIN (
    SELECT COUNT(id) AS total, tasks_id FROM ht_scope WHERE is_special <> '1' GROUP BY tasks_id
) b ON b.tasks_id = a.id
LEFT JOIN (
    SELECT COUNT(id) AS standardN, tasks_id FROM ht_scope WHERE status = '9' AND is_special <> '1' GROUP BY tasks_id
) d ON d.tasks_id = a.id
WHERE a.id = #{tasksId}
